import assert from 'node:assert/strict';
import { test } from 'node:test';
import { evaluate } from './src/evaluator.js';

test('addition', () => assert.equal(evaluate('1 + 2'), 3));
test('precedence: mul before add', () => assert.equal(evaluate('1 + 2 * 3'), 7));
test('parentheses override precedence', () => assert.equal(evaluate('(1 + 2) * 3'), 9));
test('subtraction and division', () => assert.equal(evaluate('10 / 2 - 3'), 2));
test('nested parentheses', () => assert.equal(evaluate('2 * (3 + (4 - 1))'), 12));
test('longer expression', () => assert.equal(evaluate('2 + 3 * 4 - 10 / 5'), 12));
